module binary_counter(reset_clk, rst, en, load, data, q);

    input reset_clk;
    input rst;
    input en;
    input load;
    input [3:0] data;
    output [3:0] q;
    reg [3:0] q;

    always @(posedge reset_clk)
    begin
        if (rst)
            q <= 4'b0000;
        else if (load)
            q <= data;
        else if (en)
            q <= q + 1;
    end

endmodule
